sql.where:
p.USE_YN = 'Y' AND p.PAGE_TYPE = 'REACT' AND p.APPROVE_STATE != 'WORK'
AND p.APPROVE_STATE = #{req.approveState}
AND ( p.PAGE_NAME LIKE '%' || #{req.search} || '%' OR p.CREATE_USER_NAME LIKE '%' || #{req.search} || '%' )

